	function resetAgentState(state: AgentState) {
		state.status = "idle";
		state.task = "";
		state.toolCount = 0;
		state.elapsed = 0;
		state.lastWork = "";
		state.contextPct = 0;
		state.resolvedModel = "";
		state.textChunks = [];
		state.summary = undefined;
	}

	// ── Reset agent boxes on new message ───────────────────────────────

	pi.on("input", () => {
		// When user sends a new message, reset completed/error agents to idle
		// and remove their individual widgets so boxes display cleanly for the new task
		for (const state of agentStates.values()) {
			if (state.status === "done" || state.status === "error") {
				removeAgentWidget(state);
				resetAgentState(state);
			}
		}
		updateWidget();
	});

	// ── Reset agent boxes on /new ─────────────────────────────────────

	pi.on("session_switch", async (_event, _ctx) => {
		// /new fires session_switch — clear all agent boxes from previous session
		if (widgetCtx) {
			widgetCtx.ui.setWidget("agent-team", undefined);
		}
		removeAllAgentWidgets();
		widgetCtx = _ctx;
		for (const state of agentStates.values()) {
			resetAgentState(state);
		}
		updateWidget();
	});

	// ── Session Start ────────────────────────────

	pi.on("session_start", async (_event, _ctx) => {
		applyExtensionDefaults(import.meta.url, _ctx);
		// Clear widgets from previous session
		if (widgetCtx) {
			widgetCtx.ui.setWidget("agent-team", undefined);
		}
		removeAllAgentWidgets();
		widgetCtx = _ctx;
		contextWindow = _ctx.model?.contextWindow || 0;

		// Wipe old agent session files so subagents start fresh
		const sessDir = join(_ctx.cwd, ".pi", "agent-sessions");
		if (existsSync(sessDir)) {
			for (const f of readdirSync(sessDir)) {
				if (f.endsWith(".json")) {
					try { unlinkSync(join(sessDir, f)); } catch {}
				}
			}
		}

		loadAgents(_ctx.cwd);

		// Default to first team — use /agents-team to switch
		const teamNames = Object.keys(teams);
		if (teamNames.length > 0) {
			activateTeam(teamNames[0]);
		}

		// All tools remain visible — dispatcher can use any registered tool directly

		_ctx.ui.setStatus("agent-team", `Team: ${activeTeamName} (${agentStates.size})`);
		updateWidget();

		// ── Expose global hooks for escape-cancel integration ────────────
		// Team agents also have running subprocesses that should be killed
		// on double-ESC. We reuse __piKillAllSubagents-style hook naming but
		// scoped to team procs. The escape-cancel extension checks these.
		(globalThis as any).__piKillTeamProcs = (): number => {
			let killed = 0;
			for (const [, state] of agentStates) {
				if (state.proc && state.status === "running") {
					try { state.proc.kill("SIGTERM"); } catch {}
					killed++;
				}
			}
			return killed;
		};
		(globalThis as any).__piHasRunningTeam = (): boolean => {
			for (const [, state] of agentStates) {
				if (state.status === "running") return true;
			}
			return false;
		};

		// Use footer.ts for footer — do not overwrite; widget uses placement: belowEditor

		// Register nav providers for F-key navigation
		const providers = ((globalThis as any).__piNavProviders = (globalThis as any).__piNavProviders || []);

		// Task list nav provider (first priority when tasks exist)
		providers.push({
			isActive: () => {
				const tl = (globalThis as any).__piTaskList as TaskListInfo | null;
				return !!(tl && tl.tasks.length > 0);
			},
			selectPrev: (ctx: any) => {
				if (!ctx.hasUI) return;
				widgetCtx = ctx;
				const tl = (globalThis as any).__piTaskList as TaskListInfo | null;
				if (!tl || tl.tasks.length === 0) return;
				if (taskListState.selectedIndex < 0) {
					taskListState = navEnter(taskListState, tl.tasks.length);
				} else {
					taskListState = navUp(taskListState);
				}
				updateWidget();
			},
			selectNext: (ctx: any) => {
				if (!ctx.hasUI) return;
				widgetCtx = ctx;
				const tl = (globalThis as any).__piTaskList as TaskListInfo | null;
				if (!tl || tl.tasks.length === 0) return;
				if (taskListState.selectedIndex < 0) {
					taskListState = navEnter(taskListState, tl.tasks.length);
				} else {
					taskListState = navDown(taskListState, tl.tasks.length);
				}
				updateWidget();
			},
			showDetail: async (_ctx: any) => {
				// Could open /tasks overlay in the future
			},
			exitSelection: (ctx: any) => {
				if (!ctx.hasUI) return;
				widgetCtx = ctx;
				taskListState = navExit(taskListState);
				updateWidget();
			},
		});

		// Agent pills nav provider
		providers.push({
			isActive: () => {
				const active = Array.from(agentStates.values()).filter(a => a.status !== "idle");
				return active.length > 0;
			},
			selectPrev: selectPrev,
			selectNext: selectNext,
			showDetail: async (ctx: any) => {
				if (!ctx.hasUI) return;
				const active = Array.from(agentStates.values()).filter(
					(a) => a.status !== "idle",
				);
				const count = active.length;
				if (count === 0 || selectedAgentIndex < 0 || selectedAgentIndex >= count) return;
				const agent = active[selectedAgentIndex];
				if (!agent) return;
				await showAgentDetail(ctx, agent);
			},
			exitSelection: exitSelection,
		});
	});
}

// ABOUTME: Cycles operational modes (NORMAL/PLAN/SPEC/PIPELINE/TEAM/CHAIN) via Shift+Tab.
// ABOUTME: Gates which extension's before_agent_start fires and injects PLAN/SPEC prompts.

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { Text } from "@mariozechner/pi-tui";
import { outputLine } from "./lib/output-box.ts";
import { applyExtensionDefaults } from "./lib/themeMap.ts";
import { MODES, nextMode, modeLabel, modeBgAnsi, modeTextAnsi, type Mode } from "./lib/mode-cycler-logic.ts";
import { PLAN_PROMPT, SPEC_PROMPT, buildNormalPrompt } from "./lib/mode-prompts.ts";
import { writeFileSync } from "fs";
import { showBanner, isBannerVisible } from "./agent-banner.ts";

const MODE_FILE = "/tmp/pi-current-mode.txt";


export default function (pi: ExtensionAPI) {
	let currentMode: Mode = "NORMAL";

	function updateWidgets(mode: Mode, ctx: ExtensionContext) {
		if (!ctx.hasUI) return;

		if (mode === "NORMAL") {
			ctx.ui.setWidget("mode-block", undefined);
			// Re-set agent-banner after clearing mode-block to ensure correct rendering order
			// Only re-set if banner was previously visible (not hidden by user input)
			if (isBannerVisible()) {
				showBanner(ctx);
			}
			return;
		}

		// Mode block — full-width colored banner with mode name
		// Uses theme accent color (same as model name in footer)
		ctx.ui.setWidget(
			"mode-block",
			(_tui, _theme) => ({
				invalidate() {},
				render(width: number): string[] {
					const bg = modeBgAnsi(mode);
					const text = modeTextAnsi(mode);
					const reset = "\x1b[0m";
					const label = ` ${mode} `;
					const pad = " ".repeat(Math.max(0, width - label.length));
					return [bg + text + label + pad + reset];
				},
			}),
			{ placement: "aboveEditor" },
		);

		// Re-set agent-banner after setting mode-block to ensure it renders above the bar
		// This maintains the visual hierarchy: agent-banner (logo) → mode-block (bar) → editor
		// Only re-set if banner was previously visible (not hidden by user input)
		if (isBannerVisible()) {
			showBanner(ctx);
		}
	}

	// Expose refresh function so other extensions (e.g. agent-team) can re-pin
	// the mode-block as the last aboveEditor widget (closest to the editor input).
	function refreshModeBlock(ctx: ExtensionContext) {
		updateWidgets(currentMode, ctx);
	}

	function setMode(mode: Mode, ctx: ExtensionContext) {
		currentMode = mode;
		(globalThis as any).__piCurrentMode = mode;

		// Write to temp file for statusline
		try { writeFileSync(MODE_FILE, mode, "utf-8"); } catch {}

		if (ctx.hasUI) {
			ctx.ui.setStatus("mode", modeLabel(mode));
		}

		// Publish refresh callback so other aboveEditor widgets can re-pin the mode bar
		(globalThis as any).__piRefreshModeBlock = () => refreshModeBlock(ctx);

		updateWidgets(mode, ctx);
	}

	// ── Shift+Tab: cycle forward ──────────────────

	pi.registerShortcut("shift+tab", {
		description: "Cycle operational mode",
		handler: async (ctx) => {
			setMode(nextMode(currentMode), ctx);
		},
	});

	// ── /thinking command ─────────────────────────

	const THINKING_LEVELS = ["off", "minimal", "low", "medium", "high", "xhigh"];

	pi.registerCommand("thinking", {
		description: "Set thinking level: /thinking or /thinking <LEVEL>",
		handler: async (args, ctx) => {
			if (!ctx.hasUI) return;

			const arg = args.trim().toLowerCase();
			if (arg && THINKING_LEVELS.includes(arg)) {
				pi.setThinkingLevel(arg);
				ctx.ui.notify(`Thinking: ${arg}`);
				return;
			}

			if (arg) {
				ctx.ui.notify(`Unknown level: ${arg}. Valid: ${THINKING_LEVELS.join(", ")}`, "error");
				return;
			}

			// Picker
			const current = pi.getThinkingLevel();
			const items = THINKING_LEVELS.map(l => {
				const active = l === current ? " (active)" : "";
				return `${l}${active}`;
			});
			const selected = await ctx.ui.select("Select Thinking Level", items);
			if (!selected) return;

			const level = selected.split(/\s/)[0];
			pi.setThinkingLevel(level);
			ctx.ui.notify(`Thinking: ${level}`);
		},
		autocomplete: (partial) => {
			return THINKING_LEVELS.filter(l => l.startsWith(partial.toLowerCase()));
		},
	});

	// ── /mode command ─────────────────────────────

	pi.registerCommand("mode", {
		description: "Set mode: /mode or /mode <MODE>",
		handler: async (args, ctx) => {
			if (!ctx.hasUI) return;

			const arg = args.trim().toUpperCase();
			if (arg && MODES.includes(arg as Mode)) {
				setMode(arg as Mode, ctx);
				return;
			}

			if (arg) {
				ctx.ui.notify(`Unknown mode: ${arg}. Valid: ${MODES.join(", ")}`, "error");
				return;
			}

			// Picker
			const items = MODES.map(m => {
				const active = m === currentMode ? " (active)" : "";
				return `${m}${active}`;
			});
			const selected = await ctx.ui.select("Select Mode", items);
			if (!selected) return;

			const name = selected.split(/\s/)[0] as Mode;
			setMode(name, ctx);
		},
	});

	// ── set_mode tool (autonomous mode switching) ──

	pi.registerTool({
		name: "set_mode",
		label: "Set Mode",
		description: "Switch the operational mode. Call this from NORMAL mode to activate PLAN, SPEC, TEAM, CHAIN, or PIPELINE based on task classification.",
		parameters: Type.Object({
			mode: Type.String({ description: "Target mode: NORMAL, PLAN, SPEC, PIPELINE, TEAM, or CHAIN" }),
			reason: Type.Optional(Type.String({ description: "Why this mode was chosen" })),
		}),

		async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
			const { mode: target, reason } = params as { mode: string; reason?: string };
			const upper = target.toUpperCase();

			if (!MODES.includes(upper as Mode)) {
				return {
					content: [{ type: "text", text: `Unknown mode: ${target}. Valid: ${MODES.join(", ")}` }],
					details: { error: true },
				};
			}

			setMode(upper as Mode, ctx);
			const msg = reason
				? `Mode set to ${upper}. Reason: ${reason}`
				: `Mode set to ${upper}.`;

			return {
				content: [{ type: "text", text: msg }],
				details: { mode: upper, reason },
			};
		},

		renderCall(args, theme) {
			const target = (args as any).mode || "?";
			const reason = (args as any).reason || "";
			const preview = reason.length > 50 ? reason.slice(0, 47) + "..." : reason;
			const text =
				theme.fg("toolTitle", theme.bold("set_mode ")) +
				theme.fg("accent", target.toUpperCase()) +
				(preview ? theme.fg("dim", " — ") + theme.fg("muted", preview) : "");
			return new Text(outputLine(theme, "accent", text), 0, 0);
		},

		renderResult(result, _options, theme) {
			const text = result.content[0];
			const msg = text?.type === "text" ? text.text : "";
			return new Text(outputLine(theme, "success", msg), 0, 0);
		},
	});

	// ── System prompt injection per mode ─────────

	pi.on("before_agent_start", async (_event, _ctx) => {
		if (currentMode === "NORMAL") {
			const g = globalThis as any;
			const scoutId = typeof g.__piScoutId === "number" ? g.__piScoutId : null;
			return { systemPrompt: buildNormalPrompt({
				commanderAvailable: !!g.__piCommanderAvailable,
				activeChain: g.__piActiveChain || null,
				activePipeline: g.__piActivePipeline || null,
				scoutId,
			})};
		}
		if (currentMode === "PLAN") return { systemPrompt: PLAN_PROMPT };
		if (currentMode === "SPEC") return { systemPrompt: SPEC_PROMPT };
		return {};
	});

	// ── Session init ──────────────────────────────

	pi.on("session_start", async (_event, ctx) => {
		applyExtensionDefaults(import.meta.url, ctx);
		currentMode = "NORMAL";
		(globalThis as any).__piCurrentMode = "NORMAL";
		(globalThis as any).__piRefreshModeBlock = () => refreshModeBlock(ctx);
		try { writeFileSync(MODE_FILE, "NORMAL", "utf-8"); } catch {}
		if (ctx.hasUI) {
			ctx.ui.setStatus("mode", "");
		}
		updateWidgets("NORMAL", ctx);
	});

	// ── Session switch (/new) ──────────────────────

	pi.on("session_switch", async (_event, ctx) => {
		// Re-apply current mode widgets after banner is shown to ensure correct rendering order
		// The banner is shown in agent-banner.ts's session_switch handler, so we need to
		// re-set widgets here to ensure mode-block (if any) renders before banner is re-set
		// Use process.nextTick to ensure banner's session_switch handler runs first
		process.nextTick(() => {
			updateWidgets(currentMode, ctx);
		});
	});
}

/**
 * Agent Switcher - Cycle between specialized agents with keyboard shortcuts
 * 
 * Shortcuts:
 *   Ctrl+Shift+1 → Herald (orchestrator)
 *   Ctrl+Shift+2 → Plan (planner)  
 *   Ctrl+Shift+3 → Build (executor)
 *   Ctrl+Shift+0 → Clear agent override
 *   Ctrl+Shift+Tab → Cycle forward
 *   Ctrl+Shift+Shift+Tab → Cycle backward
 * 
 * Shows current agent in footer status.
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

const STATUS_KEY = "agent-switcher";

interface AgentDefinition {
  id: string;
  name: string;
  shortcut: string;
  systemPrompt: string;
  description: string;
}

const AGENTS: AgentDefinition[] = [
  {
    id: "herald",
    name: "HERALD",
    shortcut: "ctrl+shift+1",
    description: "Orchestrator - coordinates explore → plan → execute → review",
    systemPrompt: `You are operating in HERALD mode - the orchestrator coordinator.

Your role:
- Receive user requests and assess scope (quick/medium/large)
- Delegate to specialized agents via subagent tool
- Route: Scout (explore) → Sage/Plan (plan) → Forge/Build (execute) → Ward/Arbiter (review)
- Present gates to user and wait for approval before proceeding
- NEVER write code or read files directly - delegate everything

Key behaviors:
- Use /agent switch to change modes
- Use subagent tool to delegate tasks
- Always use question tool for user confirmations
- Report findings and wait for approval before next step`,
  },
  {
    id: "plan",
    name: "PLAN",
    shortcut: "ctrl+shift+2",
    description: "Strategic planner using spec-driven methodology",
    systemPrompt: `You are operating in PLAN mode - the strategic planner.

Your role:
- Load spec-driven skill for structured planning
- Produce spec, design, and tasks artifacts
- Consume learnings from Scout exploration
- NEVER write code - only planning

Key behaviors:
- Use /agent switch to change modes
- Load spec-driven skill for methodology
- Return artifact content in JSON envelope
- Ask Herald to route to Forge when ready to execute`,
  },
  {
    id: "build",
    name: "BUILD",
    shortcut: "ctrl+shift+3",
    description: "Executor - the only agent that writes code",
    systemPrompt: `You are operating in BUILD mode - the executor.

Your role:
- Read tasks from .specs/ and write code
- Execute one task at a time, emit progress after each
- Mark tasks complete in tasks.md
- NEVER re-explore - the plan has all research

Key behaviors:
- Use /agent switch to change modes
- Execute tasks from tasks.md sequentially
- Mark checkboxes as done: - [ ] → - [x]
- Run tests/lint before marking task complete
- Propose commit message when done`,
  },
];

// Active agent (null = no override)
let activeAgentId: string | null = null;

function getActiveAgent(): AgentDefinition | null {
  if (!activeAgentId) return null;
  return AGENTS.find((a) => a.id === activeAgentId) || null;
}

function formatStatus(): string {
  const agent = getActiveAgent();
  if (!agent) return "";
  return `[${agent.name}]`;
}

function switchToAgent(agentId: string | null, ctx: any) {
  activeAgentId = agentId;

  const agent = getActiveAgent();
  if (agent) {
    ctx.ui.setStatus(STATUS_KEY, formatStatus());
    ctx.ui.notify(`Agent: ${agent.name} - ${agent.description}`, "info");
  } else {
    ctx.ui.setStatus(STATUS_KEY, "");
    ctx.ui.notify("Agent override cleared", "info");
  }
}

export default function (pi: ExtensionAPI) {
  // Register keyboard shortcuts for each agent
  AGENTS.forEach((agent, index) => {
    pi.registerShortcut(agent.shortcut, {
      description: `Switch to ${agent.name} (${agent.description})`,
      handler: (ctx) => switchToAgent(agent.id, ctx),
    });
  });

  // Clear override
  pi.registerShortcut("ctrl+shift+0", {
    description: "Clear agent override",
    handler: (ctx) => switchToAgent(null, ctx),
  });

  // Cycle forward (skip the "none" state)
  pi.registerShortcut("ctrl+shift+tab", {
    description: "Cycle to next agent",
    handler: (ctx) => {
      const agent = getActiveAgent();
      const currentIndex = agent ? AGENTS.findIndex((a) => a.id === agent.id) : -1;
      const nextIndex = (currentIndex + 1) % AGENTS.length;
      switchToAgent(AGENTS[nextIndex].id, ctx);
    },
  });

  // Cycle backward
  pi.registerShortcut("ctrl+shift+shift+tab", {
    description: "Cycle to previous agent",
    handler: (ctx) => {
      const agent = getActiveAgent();
      const currentIndex = agent ? AGENTS.findIndex((a) => a.id === agent.id) : 0;
      const prevIndex = (currentIndex - 1 + AGENTS.length) % AGENTS.length;
      switchToAgent(AGENTS[prevIndex].id, ctx);
    },
  });

  // Commands for explicit switching
  pi.registerCommand("herald", {
    description: "Switch to Herald (orchestrator)",
    handler: async (_args, ctx) => switchToAgent("herald", ctx),
  });

  pi.registerCommand("plan", {
    description: "Switch to Plan (planner)",
    handler: async (_args, ctx) => switchToAgent("plan", ctx),
  });

  pi.registerCommand("build", {
    description: "Switch to Build (executor)",
    handler: async (_args, ctx) => switchToAgent("build", ctx),
  });

  pi.registerCommand("agent-clear", {
    description: "Clear agent override",
    handler: async (_args, ctx) => switchToAgent(null, ctx),
  });

  // Show current agent on session start
  pi.on("session_start", async (_event, ctx) => {
    const agent = getActiveAgent();
    if (agent) {
      ctx.ui.setStatus(STATUS_KEY, formatStatus());
    }
  });

  // Inject agent system prompt on each turn
  pi.on("before_agent_start", async (event, ctx) => {
    const agent = getActiveAgent();
    if (!agent) return;

    return {
      systemPrompt: event.systemPrompt + "\n\n" + agent.systemPrompt,
    };
  });
}

