/**
 * @runecraft/familiar — Shared constants and defaults
 */

// Default subagent model (fast, cheap for subagents)
export const DEFAULT_SUBAGENT_MODEL = "opencode-go/deepseek-v4-flash";

// Session storage directory for subagent sessions
export const SESSION_DIR = ".pi/agent-sessions";

// Config filenames
export const TEAMS_FILE = "teams.yaml";
export const CHAIN_FILE = "agent-chain.yaml";

// Agent models (from opencode)
export const AGENT_MODELS: Record<string, string> = {
  herald: "opencode-go/minimax-m2.7",
  scout: "opencode-go/deepseek-v4-flash",
  sage: "opencode-go/deepseek-v4-pro",
  forge: "opencode-go/minimax-m2.7",
  ward: "opencode-go/deepseek-v4-flash",
  arbiter: "opencode-go/deepseek-v4-flash",
};

// ANSI color codes for widget status backgrounds
export const STATUS_BG: Record<string, string> = {
  running: "\x1b[48;2;26;58;92m",   // dark steel blue
  done:    "\x1b[48;2;35;50;55m",    // dark teal-gray
  error:   "\x1b[48;2;70;35;35m",    // dark muted red
  idle:    "\x1b[48;2;40;40;50m",    // dark gray
};

export const RESET_BG = "\x1b[49m";
export const WHITE_BOLD = "\x1b[1;97m";
export const RESET_ALL = "\x1b[0m";

// Display helpers
export function displayName(name: string): string {
  return name.split("-").map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
}

export function abbreviateAgentName(name: string): string {
  const parts = name.split("-");
  if (parts.length > 1) {
    return parts.map(w => w.charAt(0).toUpperCase()).join("");
  }
  return name.toUpperCase();
}

// Status icon (unicode)
export function statusIcon(status: string): string {
  switch (status) {
    case "running": return "🔵";
    case "done": return "⏳";
    case "error": return "⛔";
    default: return "⚪";
  }
}

/**
 * @runecraft/familiar — Context window monitoring
 */

/**
 * Determine context budget level based on usage percentage
 */
export function contextBudgetLevel(pct: number): "normal" | "warn" | "critical" {
  if (pct >= 95) return "critical";
  if (pct >= 80) return "warn";
  return "normal";
}

/**
 * Check if error message indicates context loss
 */
export function isContextLossError(msg: string): boolean {
  const patterns = [
    "context_overflow",
    "too many tokens",
    "maximum context",
    "context limit",
    "token limit",
    "maximum tokens",
  ];
  return patterns.some(p => msg.toLowerCase().includes(p));
}

/**
 * Get color for context budget percentage
 */
export function contextBudgetColor(pct: number): string {
  if (pct >= 95) return "error";
  if (pct >= 80) return "warning";
  return "success";
}

/**
 * Format elapsed time as mm:ss
 */
export function formatElapsed(ms: number): string {
  const seconds = Math.floor(ms / 1000);
  const minutes = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${minutes}:${secs.toString().padStart(2, "0")}`;
}

