// ABOUTME: Sequential chain execution with $INPUT chaining using tmux-delegate.
// ABOUTME: Primary agent runs chain steps sequentially, passing each output as $INPUT to the next.

/**
 * agent-chain — Sequential chain execution
 *
 * Chains are defined in agent-chain.yaml and execute agents sequentially.
 * Each step receives $INPUT = output from previous step, $ORIGINAL = original user input.
 *
 * Usage:
 *   /chain <name>        — execute named chain
 *   /chain-list          — list available chains
 *
 * Tool: run_chain
 *   { name: "plan-build-review", input: "Build auth feature" }
 *
 * Dependencies: tmux-delegate (for delegate tool)
 */

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { readFileSync, existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

interface ChainStep {
  agent: string;
  prompt: string;
}

interface ChainDef {
  description: string;
  steps: ChainStep[];
}

// ─── YAML Parser (minimal, no external deps) ───────────────────────────────

function parseChainsYaml(raw: string): Record<string, ChainDef> {
  const chains: Record<string, ChainDef> = {};
  let current: string | null = null;
  let inSteps = false;
  let steps: ChainStep[] = [];
  let description = "";

  for (const line of raw.split("\n")) {
    // Skip empty lines at top
    if (current === null && !line.trim()) continue;

    // Chain header: "chain-name:"
    const chainMatch = line.match(/^(\S[^:]*):$/);
    if (chainMatch) {
      // Save previous chain
      if (current) {
        chains[current] = { description, steps };
      }
      current = chainMatch[1].trim();
      steps = [];
      description = "";
      inSteps = false;
      continue;
    }

    // Description line
    const descMatch = line.match(/^\s+description:\s*"?([^"]*)"?\s*$/);
    if (descMatch && current) {
      description = descMatch[1].trim();
      continue;
    }

    // Steps block starts
    if (line.match(/^\s+steps:\s*$/) && current) {
      inSteps = true;
      continue;
    }

    // Step agent: "    - agent: scout"
    const agentMatch = line.match(/^\s+-\s+agent:\s*(\S+)\s*$/);
    if (agentMatch && inSteps) {
      steps.push({ agent: agentMatch[1], prompt: "" });
      continue;
    }

    // Step prompt: "      prompt: |" or "      prompt: \"...\"
    const promptMatch = line.match(/^\s+prompt:\s*(.+)\s*$/);
    if (promptMatch && inSteps && steps.length > 0) {
      steps[steps.length - 1].prompt = promptMatch[1].trim();
    }
  }

  // Save last chain
  if (current) {
    chains[current] = { description, steps };
  }

  return chains;
}

// ─── Input Resolution ─────────────────────────────────────────────────────

function resolveInput(
  prompt: string,
  original: string,
  stepOutput: string,
): string {
  return prompt
    .replace(/\$ORIGINAL/g, original)
    .replace(/\$INPUT/g, stepOutput);
}

// ─── Chain Loading ──────────────────────────────────────────────────────

function loadChains(cwd: string): Record<string, ChainDef> {
  const extDir = dirname(fileURLToPath(import.meta.url));

  // Look for agent-chain.yaml in multiple locations
  const locations = [
    join(cwd, "agents", "agent-chain.yaml"),
    join(cwd, ".pi", "agents", "agent-chain.yaml"),
    join(extDir, "..", "agents", "agent-chain.yaml"),
    join(extDir, "..", "..", "agents", "agent-chain.yaml"),
  ];

  for (const loc of locations) {
    if (existsSync(loc)) {
      try {
        return parseChainsYaml(readFileSync(loc, "utf-8"));
      } catch {}
    }
  }

  return {};
}

// ─── Extension ────────────────────────────────────────────────────────────

export default function (pi: ExtensionAPI) {
  let chains: Record<string, ChainDef> = {};
  let currentOriginal = "";

  // Load chains on session start
  pi.on("session_start", async (_event, ctx) => {
    chains = loadChains(ctx.cwd);
    (globalThis as any).__piActiveChain = null;
  });

  // ── run_chain Tool ─────────────────────────────────────────────────────

  pi.registerTool({
    name: "run_chain",
    label: "Run Chain",
    description:
      "Execute a pre-defined chain of agents sequentially. " +
      "Each step's output becomes $INPUT for the next step. " +
      "Use /chain-list to see available chains.",
    promptSnippet: "Execute a chain workflow (scout → sage → forge → arbiter)",

    parameters: Type.Object({
      name: Type.String({ description: "Chain name (e.g., plan-build-review)" }),
      input: Type.Optional(
        Type.String({ description: "Original input for $ORIGINAL (defaults to conversation context)" }),
      ),
    }),

    async execute(_toolCallId, params, _signal, onUpdate, ctx) {
      const { name, input } = params as { name: string; input?: string };

      // Get chains if not loaded
      if (Object.keys(chains).length === 0) {
        chains = loadChains(ctx.cwd);
      }

      const chain = chains[name];
      if (!chain) {
        return {
          content: [
            {
              type: "text",
              text: `Chain "${name}" not found. Available: ${Object.keys(chains).join(", ") || "none"}`,
            },
          ],
          isError: true,
        };
      }

      currentOriginal = input || currentOriginal || "Task";
      (globalThis as any).__piActiveChain = name;

      onUpdate?.({
        content: [
          {
            type: "text",
            text: `[chain] Starting "${name}" — ${chain.description}`,
          },
        ],
      });

      const results: string[] = [];
      let stepInput = currentOriginal;

      for (let i = 0; i < chain.steps.length; i++) {
        const step = chain.steps[i];
        const resolvedPrompt = resolveInput(step.prompt, currentOriginal, stepInput);

        onUpdate?.({
          content: [
            {
              type: "text",
              text: `[chain] Step ${i + 1}/${chain.steps.length}: ${step.agent}`,
            },
          ],
        });

        // Execute step via delegate tool
        const delegateResult = await (ctx as any).callTool(
          "delegate",
          { agent: step.agent, task: resolvedPrompt, context: "" },
          undefined,
          undefined,
        );

        const output =
          delegateResult?.content?.[0]?.text ||
          delegateResult?.content?.[0]?.text ||
          "No output";

        results.push(output);
        stepInput = output; // Pass as $INPUT to next step
      }

      (globalThis as any).__piActiveChain = null;

      return {
        content: [
          {
            type: "text",
            text: results.join("\n\n---\n\n"),
          },
        ],
        details: {
          chain: name,
          steps: chain.steps.length,
          results: results.length,
        },
      };
    },
  });

  // ── /chain Command ───────────────────────────────────────────────────────

  pi.registerCommand("chain", {
    description: "Execute a chain: /chain <name> [input]",
    handler: async (args, ctx) => {
      const parts = args.trim().split(/\s+/);
      const name = parts[0];
      const input = parts.slice(1).join(" ");

      if (!name) {
        ctx.ui.notify("Usage: /chain <name> [input]", "error");
        return;
      }

      // Load chains if needed
      if (Object.keys(chains).length === 0) {
        chains = loadChains(ctx.cwd);
      }

      const chain = chains[name];
      if (!chain) {
        ctx.ui.notify(
          `Chain "${name}" not found. Available: ${Object.keys(chains).join(", ")}`,
          "error",
        );
        return;
      }

      // Run chain via tool
      const result = await (ctx as any).callTool(
        "run_chain",
        { name, input: input || undefined },
        undefined,
        undefined,
      );

      ctx.ui.notify(`Chain "${name}" complete`, "success");
    },
  });

  // ── /chain-list Command ─────────────────────────────────────────────────

  pi.registerCommand("chain-list", {
    description: "List available chains",
    handler: async (_args, ctx) => {
      if (Object.keys(chains).length === 0) {
        chains = loadChains(ctx.cwd);
      }

      const names = Object.entries(chains)
        .map(([name, def]) => {
          const steps = def.steps.map((s) => s.agent).join(" → ");
          return `- **${name}**: ${def.description} (${steps})`;
        })
        .join("\n");

      ctx.ui.notify(
        names || "No chains defined. Add agent-chain.yaml to agents/",
        "info",
      );
    },
  });

  // ── Expose for other extensions ──────────────────────────────────────────

  (globalThis as any).__piGetChains = () => chains;
}

// ABOUTME: Shift+Tab cycles between NORMAL and PLAN modes.
// ABOUTME: PLAN mode injects spec-driven skill into Sage prompts.

/**
 * plan-mode — PLAN mode for spec-driven workflow
 *
 * Shift+Tab cycles: NORMAL ↔ PLAN
 * PLAN mode injects spec-driven skill into system prompt
 * Sage receives context to use spec-driven methodology
 *
 * Usage:
 *   Shift+Tab        — cycle mode
 *   /plan            — set PLAN mode
 *   /mode            — show/set mode
 *
 * Tool: set_mode
 *   { mode: "PLAN" }
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { readFileSync, existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

type Mode = "NORMAL" | "PLAN";

const MODES: Mode[] = ["NORMAL", "PLAN"];

function nextMode(current: Mode): Mode {
  const idx = MODES.indexOf(current);
  return MODES[(idx + 1) % MODES.length];
}

function modeLabel(mode: Mode): string {
  return mode === "NORMAL" ? "" : `[${mode}]`;
}

// ─── PLAN Mode System Prompt ───────────────────────────────────────────────

const PLAN_PROMPT = `
## PLAN Mode Active

You are now in **PLAN mode**. Use the spec-driven planning methodology.

### When to Use PLAN Mode
- User wants to plan a new feature
- Planning with Sage for structured specs, design, and tasks

### Your Role in PLAN Mode
1. Gather requirements from user
2. Delegate to **Sage** with the spec-driven skill:
   \`delegate({ agent: "sage", task: "<requirement>", context: "<context>" })\`
3. Present Sage's artifacts to user for approval
4. If approved, proceed with execution

### spec-driven Skill
Load and apply the spec-driven skill:
- **SPECIFY**: Write spec.md (problem, goals, scope, constraints)
- **DESIGN**: Write design.md (architecture, decisions, risks)
- **TASKS**: Write tasks.md (checklist with acceptance criteria)

### Key Principles
- Always delegate planning to Sage (never plan yourself in PLAN mode)
- Use \`delegate\` tool to invoke Sage
- Present results to user before proceeding
- Ask clarifying questions before delegating

## Skills Available
- spec-driven.md — structured planning methodology

## Commands
- /plan — stay in PLAN mode
- /normal — return to NORMAL mode
- Shift+Tab — toggle mode
`;

// ─── Skill Loading ────────────────────────────────────────────────────────

function loadSkill(skillName: string, cwd: string): string {
  const extDir = dirname(fileURLToPath(import.meta.url));

  const locations = [
    join(cwd, ".agents", "skills", `${skillName}.md`),
    join(cwd, "skills", `${skillName}.md`),
    join(extDir, "..", "..", "skills", `${skillName}.md`),
    join(extDir, "..", "skills", `${skillName}.md`),
  ];

  for (const loc of locations) {
    if (existsSync(loc)) {
      try {
        return readFileSync(loc, "utf-8");
      } catch {}
    }
  }

  return "";
}

// ─── Extension ────────────────────────────────────────────────────────────

export default function (pi: ExtensionAPI) {
  let currentMode: Mode = "NORMAL";

  // ── Mode State ──────────────────────────────────────────────────────────

  function setMode(mode: Mode, ctx: any) {
    currentMode = mode;
    (globalThis as any).__piCurrentMode = mode;

    if (ctx.hasUI) {
      ctx.ui.setStatus("mode", modeLabel(mode));

      // Show mode block for PLAN mode
      if (mode === "PLAN") {
        ctx.ui.setWidget("plan-mode-block", (_tui: any, _theme: any) => ({
          render(width: number): string[] {
            const bg = "\x1b[48;2;26;58;92m";
            const text = "\x1b[1;97m";
            const reset = "\x1b[0m";
            const label = " PLAN ";
            const pad = " ".repeat(Math.max(0, width - label.length));
            return [bg + text + label + pad + reset];
          },
          invalidate() {},
        }), { placement: "aboveEditor" });
      } else {
        ctx.ui.setWidget("plan-mode-block", undefined);
      }
    }

    ctx.ui.notify(`Mode: ${mode}`, mode === "PLAN" ? "info" : "success");
  }

  // ── Shift+Tab: Cycle Mode ───────────────────────────────────────────────

  pi.registerShortcut("shift+tab", {
    description: "Toggle NORMAL ↔ PLAN mode",
    handler: async (ctx) => {
      setMode(nextMode(currentMode), ctx);
    },
  });

  // ── /plan Command ───────────────────────────────────────────────────────

  pi.registerCommand("plan", {
    description: "Enter PLAN mode (spec-driven)",
    handler: async (_args, ctx) => {
      setMode("PLAN", ctx);
    },
  });

  // ── /normal Command ─────────────────────────────────────────────────────

  pi.registerCommand("normal", {
    description: "Return to NORMAL mode",
    handler: async (_args, ctx) => {
      setMode("NORMAL", ctx);
    },
  });

  // ── /mode Command ───────────────────────────────────────────────────────

  pi.registerCommand("mode", {
    description: "Show or set mode: /mode or /mode <NORMAL|PLAN>",
    handler: async (args, ctx) => {
      const arg = args.trim().toUpperCase();

      if (arg && MODES.includes(arg as Mode)) {
        setMode(arg as Mode, ctx);
        return;
      }

      ctx.ui.notify(
        `Current mode: ${currentMode}. Use /mode NORMAL or /mode PLAN`,
        "info",
      );
    },
  });

  // ── set_mode Tool ───────────────────────────────────────────────────────

  pi.registerTool({
    name: "set_mode",
    label: "Set Mode",
    description: "Switch between NORMAL and PLAN mode",
    promptSnippet: "Toggle plan mode",

    parameters: Type.Object({
      mode: Type.Union([
        Type.Literal("NORMAL"),
        Type.Literal("PLAN"),
      ]),
    }),

    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      const { mode } = params as { mode: Mode };
      setMode(mode, ctx);
      return {
        content: [{ type: "text", text: `Mode set to ${mode}` }],
        details: { mode },
      };
    },
  });

  // ── before_agent_start: Inject Mode Prompt ──────────────────────────────

  pi.on("before_agent_start", async (event, ctx) => {
    if (currentMode === "NORMAL") {
      return {}; // No change
    }

    // Load spec-driven skill
    const skill = loadSkill("spec-driven", ctx.cwd);
    const skillSection = skill
      ? `\n\n## Skill: spec-driven\n\n${skill}`
      : "";

    return {
      systemPrompt:
        event.systemPrompt +
        PLAN_PROMPT +
        skillSection,
    };
  });

  // ── Session Start/Reset ─────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    currentMode = "NORMAL";
    (globalThis as any).__piCurrentMode = "NORMAL";
    if (ctx.hasUI) {
      ctx.ui.setStatus("mode", "");
    }
  });

  pi.on("session_switch", async (_event, ctx) => {
    currentMode = "NORMAL";
    (globalThis as any).__piCurrentMode = "NORMAL";
    if (ctx.hasUI) {
      ctx.ui.setWidget("plan-mode-block", undefined);
      ctx.ui.setStatus("mode", "");
    }
  });

  // ── Expose for other extensions ──────────────────────────────────────────

  (globalThis as any).__piGetMode = () => currentMode;
  (globalThis as any).__piSetMode = (mode: Mode) => {
    currentMode = mode;
    (globalThis as any).__piCurrentMode = mode;
  };
}

// ABOUTME: Pre-tool hook blocks dangerous commands and credential exposure.
// ABOUTME: Intercepts tool calls before execution to prevent security issues.

/**
 * security-guard — Pre-tool hook security blocker
 *
 * Blocks dangerous commands, credential patterns, and prompt injection.
 * Runs before tool execution to prevent damage.
 *
 * Usage: Automatically loads on session start
 *
 * Tool: security_check
 *   { command: "rm -rf /" } — check if command would be blocked
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";

// ─── Blocked Patterns ─────────────────────────────────────────────────────

interface BlockRule {
  pattern: RegExp;
  reason: string;
  severity: "critical" | "high" | "medium";
}

const BLOCK_RULES: BlockRule[] = [
  // Destructive commands
  {
    pattern: /^rm\s+-rf\s+\//,
    reason: "Recursive delete from root",
    severity: "critical",
  },
  {
    pattern: /^rm\s+-rf\s+\/home/,
    reason: "Recursive delete in home directory",
    severity: "critical",
  },
  {
    pattern: /^rm\s+-rf\s+\/tmp/,
    reason: "Recursive delete in /tmp",
    severity: "high",
  },
  {
    pattern: /^sudo\s+rm\s/,
    reason: "sudo rm command",
    severity: "high",
  },
  {
    pattern: /^dd\s+if=/,
    reason: "dd with input file (risk of disk wipe)",
    severity: "critical",
  },
  {
    pattern: /^mkfs\./,
    reason: "Format filesystem",
    severity: "critical",
  },
  {
    pattern: /^dolphin\s+sudo/,
    reason: "Dolphin with sudo",
    severity: "high",
  },
  {
    pattern: /^nautilus\s+sudo/,
    reason: "Nautilus with sudo",
    severity: "high",
  },

  // Credential patterns
  {
    pattern: /sk-[a-zA-Z0-9]{20,}/,
    reason: "OpenAI API key detected",
    severity: "critical",
  },
  {
    pattern: /ghp_[a-zA-Z0-9]{20,}/,
    reason: "GitHub personal access token detected",
    severity: "critical",
  },
  {
    pattern: /github_pat_[a-zA-Z0-9_]{20,}/,
    reason: "GitHub fine-grained token detected",
    severity: "critical",
  },
  {
    pattern: /xox[baprs]-[a-zA-Z0-9]{10,}/,
    reason: "Slack token detected",
    severity: "critical",
  },
  {
    pattern: /AKIA[0-9A-Z]{16}/,
    reason: "AWS access key ID detected",
    severity: "critical",
  },
  {
    pattern: /\.env.*PASSWORD.*=/,
    reason: "Password in .env file",
    severity: "high",
  },
  {
    pattern: /BEGIN\s+(RSA\s+)?PRIVATE\s+KEY/,
    reason: "Private key detected",
    severity: "critical",
  },

  // Prompt injection
  {
    pattern: /\x00/,
    reason: "Null byte injection",
    severity: "high",
  },
  {
    pattern: /\{\{.*\}\}/,
    reason: "Template injection attempt",
    severity: "medium",
  },
  {
    pattern: /<script[^>]*>.*<\/script>/i,
    reason: "Script injection attempt",
    severity: "high",
  },
];

// ─── Check Functions ───────────────────────────────────────────────────────

function checkBlocked(command: string): { blocked: boolean; reason?: string; severity?: string } {
  for (const rule of BLOCK_RULES) {
    if (rule.pattern.test(command)) {
      return {
        blocked: true,
        reason: rule.reason,
        severity: rule.severity,
      };
    }
  }
  return { blocked: false };
}

// ─── Extension ────────────────────────────────────────────────────────────

export default function (pi: ExtensionAPI) {
  // ── tool_call Hook ────────────────────────────────────────────────────────

  pi.on("tool_call", async (event, ctx) => {
    const toolName = event.toolCall?.name;
    const args = event.toolCall?.parameters;

    // Only check bash tool
    if (toolName !== "bash") {
      return {}; // Allow other tools
    }

    // Extract command from bash arguments
    let command = "";
    if (typeof args === "object" && args !== null) {
      const argsObj = args as any;
      command = argsObj.command || argsObj.cmd || argsObj._ || "";
    }

    if (!command) {
      return {};
    }

    const check = checkBlocked(command);
    if (check.blocked) {
      return {
        blocked: true,
        reason: `[security-guard] Blocked: ${check.reason}`,
        details: {
          severity: check.severity,
          command: command.substring(0, 50) + (command.length > 50 ? "..." : ""),
        },
      };
    }

    return {};
  });

  // ── security_check Tool ─────────────────────────────────────────────────

  pi.registerTool({
    name: "security_check",
    label: "Security Check",
    description:
      "Check if a command would be blocked by security-guard",
    promptSnippet: "Check if command is safe to run",

    parameters: Type.Object({
      command: Type.String({ description: "Command to check" }),
    }),

    async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
      const { command } = params as { command: string };
      const check = checkBlocked(command);

      if (check.blocked) {
        return {
          content: [
            {
              type: "text",
              text: `BLOCKED: ${check.reason} (${check.severity})`,
            },
          ],
          isError: true,
          details: { blocked: true, reason: check.reason, severity: check.severity },
        };
      }

      return {
        content: [{ type: "text", text: "OK: Command is not blocked" }],
        details: { blocked: false },
      };
    },
  });

  // ── Expose ─────────────────────────────────────────────────────────────

  (globalThis as any).__piSecurityCheck = checkBlocked;
}

