// ABOUTME: Pure functions for cycling operational modes.
// ABOUTME: Runecraft themed — NORMAL (default) and PLAN (spec-driven).

import { MODES, type Mode } from "./mode-cycler-logic.ts";

// ── Runecraft: Only NORMAL and PLAN modes ─────────────────────────────────

export const FAMILIAR_MODES = ["NORMAL", "PLAN"] as const;
export type FamiliarMode = typeof FAMILIAR_MODES[number];

export { MODES, type Mode };

/** Runecraft modes: NORMAL and PLAN only */
export const RUNECRAFT_MODES = FAMILIAR_MODES;

/** Advance to the next mode in the cycle. */
export function nextMode(current: FamiliarMode): FamiliarMode {
	const idx = FAMILIAR_MODES.indexOf(current as FamiliarMode);
	return FAMILIAR_MODES[(idx + 1) % FAMILIAR_MODES.length];
}

/** Go back to the previous mode. */
export function prevMode(current: FamiliarMode): FamiliarMode {
	const idx = FAMILIAR_MODES.indexOf(current as FamiliarMode);
	return FAMILIAR_MODES[(idx - 1 + FAMILIAR_MODES.length) % FAMILIAR_MODES.length];
}

// ── Colors ─────────────────────────────────────────────────────────────────

/** Theme color name for a mode. NORMAL returns empty (no color). */
export function modeColor(mode: FamiliarMode): string {
	return mode === "NORMAL" ? "" : "accent";
}

/** ANSI text color for the mode bar. */
export function modeTextAnsi(mode: FamiliarMode): string {
	return mode === "NORMAL" ? "" : "\x1b[1;97m"; // bold white
}

/** ANSI background color for the mode bar. */
export function modeBgAnsi(mode: FamiliarMode): string {
	if (mode === "NORMAL") return "";
	// Runecraft purple for PLAN mode
	return "\x1b[48;2;187;154;247m"; // purple rgb(187,154,247)
}

/** Status label for a mode. NORMAL returns empty, PLAN returns "[PLAN]". */
export function modeLabel(mode: FamiliarMode): string {
	return mode === "NORMAL" ? "" : `[${mode}]`;
}

// Re-export original functions for other extensions
import { nextMode as originalNextMode, prevMode as originalPrevMode } from "./mode-cycler-logic.ts";
import { modeColor as originalModeColor } from "./mode-cycler-logic.ts";
import { modeTextAnsi as originalModeTextAnsi } from "./mode-cycler-logic.ts";
